21	// US-038 — Creator Discover feed. Renders a header Chip toggle for
22	// "Eligible only" plus a pull-to-refresh list of CampaignCards sourced from
23	// the `list_discover_feed(p_eligible_only)` SECURITY DEFINER RPC (see the
24	// us_038 migration for rationale — a plain PostgREST embed would silently
25	// null lister_handle under the self-only users RLS policy).
26	//
27	// Persistence: the toggle state is stored in AsyncStorage under
28	// FILTER_STORAGE_KEY (spec says MMKV but Codebase Pattern #91 rules MMKV
29	// out under Expo Go; a non-secret boolean preference doesn't warrant the
30	// SecureStore ceremony either, so AsyncStorage is the right fit).
31	// Default is eligible_only=true per AC.
32	//
33	// Empty state per docs/design.md §5.5 — the "See all campaigns" action
34	// flips the toggle off (which reloads) rather than routing elsewhere.
35	
36	type DiscoverRow = Database['public']['Functions']['list_discover_feed']['Returns'][number];
37	
38	const FILTER_STORAGE_KEY = 'marketify.discoverEligibleOnly';
39	const HYDRATED_DEFAULT = true;
40	
41	function readCurrency(raw: string): 'USD' | 'EUR' | 'GBP' {
42	  return raw === 'EUR' || raw === 'GBP' ? raw : 'USD';
43	}
44	
45	export default function Feed() {
46	  // Toggle is hydrated async from AsyncStorage — until the read settles we
47	  // render with the default and flip in place once storage returns. This
48	  // matches the storage-hydration pattern from AuthProvider (Pattern #97).
49	  const [eligibleOnly, setEligibleOnly] = useState<boolean>(HYDRATED_DEFAULT);
50	  const [hydrated, setHydrated] = useState<boolean>(false);
51	
52	  const [rows, setRows] = useState<DiscoverRow[]>([]);
53	  const [loading, setLoading] = useState<boolean>(true);
54	  const [refreshing, setRefreshing] = useState<boolean>(false);
55	  const [error, setError] = useState<string | null>(null);
56	
57	  // Synchronous ref mirrors the latest toggle value so the `load` callback
58	  // never stale-captures it (Pattern #106). React state still drives the UI.
59	  const eligibleRef = useRef<boolean>(HYDRATED_DEFAULT);
60	  // Monotonic counter so rapid toggle flips don't let a stale response
61	  // overwrite fresh data — only the latest dispatch's rows hit state.
62	  const loadSeqRef = useRef<number>(0);
63	
64	  useEffect(() => {
65	    let cancelled = false;
66	    void AsyncStorage.getItem(FILTER_STORAGE_KEY).then((raw) => {
67	      if (cancelled) return;
68	      const next = raw === null ? HYDRATED_DEFAULT : raw === 'true';
69	      eligibleRef.current = next;
70	      setEligibleOnly(next);
71	      setHydrated(true);
72	    });
73	    return () => {
74	      cancelled = true;
75	    };
76	  }, []);
77	
78	  const load = useCallback(async (isRefresh: boolean) => {
79	    const seq = ++loadSeqRef.current;
80	    if (isRefresh) setRefreshing(true);
81	    else setLoading(true);
82	    setError(null);
83	
84	    const { data, error: rpcError } = await supabase.rpc('list_discover_feed', {
85	      p_eligible_only: eligibleRef.current,
86	    });
87	    if (loadSeqRef.current !== seq) return;
88	    if (rpcError) {
89	      setError("Couldn't load campaigns.");
90	      setRows([]);
91	    } else {
92	      setRows(data ?? []);
93	    }
94	    if (isRefresh) setRefreshing(false);
95	    else setLoading(false);
96	  }, []);
97	
98	  // Re-fetch whenever the toggle changes, but only after hydration — the
99	  // first effect run will otherwise fire twice (once with the default,
100	  // once with the hydrated value).
101	  useEffect(() => {
102	    if (!hydrated) return;
103	    eligibleRef.current = eligibleOnly;
104	    void load(false);
105	  }, [eligibleOnly, hydrated, load]);
106	
107	  const onToggleEligible = useCallback(() => {
108	    setEligibleOnly((prev) => {
109	      const next = !prev;
110	      void AsyncStorage.setItem(FILTER_STORAGE_KEY, next ? 'true' : 'false');
111	      return next;
112	    });
113	  }, []);
114	
115	  const onRefresh = useCallback(() => {
116	    void load(true);
117	  }, [load]);
118	
119	  const onCardPress = useCallback((id: string) => {
120	    router.push(`/(creator)/listing/${id}`);
121	  }, []);
122	
123	  return (
124	    <SafeAreaView style={styles.root}>
125	      <ScrollView
126	        contentContainerStyle={styles.scroll}
127	        refreshControl={
128	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
129	        }
130	      >
131	        <Text style={[textStyles.display, styles.header]}>Discover</Text>
132	
133	        <View style={styles.filterRow}>
134	          <Chip
135	            label="Eligible only"
136	            active={eligibleOnly}
137	            onPress={onToggleEligible}
138	            testID="chip-eligible-only"
139	          />
140	        </View>
141	
142	        {loading ? (
143	          <View style={styles.list} testID="discover-loading">
144	            <SkeletonCard />
145	            <SkeletonCard />
146	            <SkeletonCard />
147	          </View>
148	        ) : error ? (
149	          <View style={styles.emptyBox}>
150	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
151	          </View>
152	        ) : rows.length === 0 ? (
153	          <EmptyState
154	            eligibleOnly={eligibleOnly}
155	            onSeeAll={() => {
156	              if (!eligibleOnly) return;
157	              setEligibleOnly(false);
158	              void AsyncStorage.setItem(FILTER_STORAGE_KEY, 'false');
159	            }}
160	          />
161	        ) : (
162	          <View style={styles.list} testID="discover-list">
163	            {rows.map((r) => (
164	              <CampaignCard
165	                key={r.id}
166	                title={r.title}
167	                listerHandle={`@${r.lister_handle}`}
168	                priceCents={r.price_cents}
169	                currency={readCurrency(r.currency)}
170	                onPress={() => onCardPress(r.id)}
171	                testID={`campaign-card-${r.id}`}
172	              />
173	            ))}
174	          </View>
175	        )}
176	      </ScrollView>
177	    </SafeAreaView>
178	  );
179	}
180	
181	// Empty state per docs/design.md §5.5. Two action cards: "Refresh your
182	// metrics" routes to Profile (which has its own refresh affordance from
183	// US-036); "See all campaigns" flips the eligibility toggle off in place.
184	// The latter is hidden when the toggle is already off — nothing to flip.
185	function EmptyState({
186	  eligibleOnly,
187	  onSeeAll,
188	}: {
189	  eligibleOnly: boolean;
190	  onSeeAll: () => void;
191	}) {
192	  return (
193	    <View style={styles.emptyRoot} testID="discover-empty">
194	      <Text style={[textStyles.h1, styles.emptyHeadline]}>Nothing matches you — yet.</Text>
195	      <Text style={[textStyles.body, styles.emptyBody]}>
196	        {'Campaigns get added daily. Meanwhile, here\u2019s what to try.'}
197	      </Text>
198	
199	      <Pressable
200	        style={[styles.actionCard, shadows.hard]}
201	        onPress={() => router.push('/(creator)/profile')}
202	        accessibilityRole="button"
203	        accessibilityLabel="Refresh your metrics"
204	        testID="empty-action-refresh"
205	      >
206	        <Text style={[textStyles.h2, { color: colors.ink }]}>Refresh your metrics</Text>
207	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>
208	          Your follower counts may be out of date.
209	        </Text>
210	      </Pressable>
211	
212	      {eligibleOnly ? (
213	        <Pressable
214	          style={[styles.actionCard, shadows.hard]}
215	          onPress={onSeeAll}
216	          accessibilityRole="button"
217	          accessibilityLabel="See all campaigns"
218	          testID="empty-action-see-all"
219	        >
220	          <Text style={[textStyles.h2, { color: colors.ink }]}>See all campaigns</Text>
221	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
222	            Turn off the eligibility filter.
223	          </Text>
224	        </Pressable>
225	      ) : null}
226	    </View>
227	  );
228	}
